84	function resolveBundledManifestContracts(): PluginRegistrationContractEntry[] {
85	  if (process.env.VITEST) {
86	    return BUNDLED_PLUGIN_CONTRACT_SNAPSHOTS.map((entry) => ({
87	      pluginId: entry.pluginId,
88	      cliBackendIds: [...entry.cliBackendIds],
89	      providerIds: [...entry.providerIds],
90	      speechProviderIds: [...entry.speechProviderIds],
91	      realtimeTranscriptionProviderIds: [...entry.realtimeTranscriptionProviderIds],
92	      realtimeVoiceProviderIds: [...entry.realtimeVoiceProviderIds],
93	      mediaUnderstandingProviderIds: [...entry.mediaUnderstandingProviderIds],
94	      imageGenerationProviderIds: [...entry.imageGenerationProviderIds],
95	      videoGenerationProviderIds: [...entry.videoGenerationProviderIds],
96	      musicGenerationProviderIds: [...entry.musicGenerationProviderIds],
97	      webFetchProviderIds: [...entry.webFetchProviderIds],
98	      webSearchProviderIds: [...entry.webSearchProviderIds],
99	      toolNames: [...entry.toolNames],
100	    }));
101	  }
102	  return loadPluginManifestRegistry({})
103	    .plugins.filter(
104	      (plugin) =>
105	        plugin.origin === "bundled" &&
106	        (plugin.cliBackends.length > 0 ||
107	          plugin.providers.length > 0 ||
108	          (plugin.contracts?.speechProviders?.length ?? 0) > 0 ||
109	          (plugin.contracts?.realtimeTranscriptionProviders?.length ?? 0) > 0 ||
110	          (plugin.contracts?.realtimeVoiceProviders?.length ?? 0) > 0 ||
111	          (plugin.contracts?.mediaUnderstandingProviders?.length ?? 0) > 0 ||
112	          (plugin.contracts?.imageGenerationProviders?.length ?? 0) > 0 ||
113	          (plugin.contracts?.videoGenerationProviders?.length ?? 0) > 0 ||
114	          (plugin.contracts?.musicGenerationProviders?.length ?? 0) > 0 ||
115	          (plugin.contracts?.webFetchProviders?.length ?? 0) > 0 ||
116	          (plugin.contracts?.webSearchProviders?.length ?? 0) > 0 ||
117	          (plugin.contracts?.tools?.length ?? 0) > 0),
118	    )
119	    .map((plugin) => ({
120	      pluginId: plugin.id,
121	      cliBackendIds: uniqueStrings(plugin.cliBackends),
122	      providerIds: uniqueStrings(plugin.providers),
123	      speechProviderIds: uniqueStrings(plugin.contracts?.speechProviders ?? []),
124	      realtimeTranscriptionProviderIds: uniqueStrings(
125	        plugin.contracts?.realtimeTranscriptionProviders ?? [],
126	      ),
127	      realtimeVoiceProviderIds: uniqueStrings(plugin.contracts?.realtimeVoiceProviders ?? []),
128	      mediaUnderstandingProviderIds: uniqueStrings(
129	        plugin.contracts?.mediaUnderstandingProviders ?? [],
