131	      imageGenerationProviderIds: uniqueStrings(plugin.contracts?.imageGenerationProviders ?? []),
132	      videoGenerationProviderIds: uniqueStrings(plugin.contracts?.videoGenerationProviders ?? []),
133	      musicGenerationProviderIds: uniqueStrings(plugin.contracts?.musicGenerationProviders ?? []),
134	      webFetchProviderIds: uniqueStrings(plugin.contracts?.webFetchProviders ?? []),
135	      webSearchProviderIds: uniqueStrings(plugin.contracts?.webSearchProviders ?? []),
136	      toolNames: uniqueStrings(plugin.contracts?.tools ?? []),
137	    }));
