140	function resolveBundledProviderContractPluginIdsByProviderId(): Map<string, string[]> {
141	  const result = new Map<string, string[]>();
142	  for (const entry of resolveBundledManifestContracts()) {
143	    for (const providerId of entry.providerIds) {
144	      const existing = result.get(providerId) ?? [];
145	      if (!existing.includes(entry.pluginId)) {
146	        existing.push(entry.pluginId);
147	      }
148	      result.set(providerId, existing);
149	    }
150	  }
151	  return result;
152	}
