230	function formatBundledCapabilityPluginLoadError(params: {
231	  pluginId: string;
232	  capabilityLabel: string;
233	  registry: BundledCapabilityRuntimeRegistry;
234	}): Error {
235	  const plugin = params.registry.plugins.find((entry) => entry.id === params.pluginId);
236	  const diagnostics = params.registry.diagnostics
237	    .filter((entry) => entry.pluginId === params.pluginId)
238	    .map((entry) => entry.message);
239	  const detailParts = plugin
240	    ? [
241	        `status=${plugin.status}`,
242	        ...(plugin.error ? [`error=${plugin.error}`] : []),
243	        `providerIds=[${plugin.providerIds.join(", ")}]`,
244	        `webFetchProviderIds=[${plugin.webFetchProviderIds.join(", ")}]`,
245	        `webSearchProviderIds=[${plugin.webSearchProviderIds.join(", ")}]`,
246	      ]
247	    : ["plugin record missing"];
248	  if (diagnostics.length > 0) {
249	    detailParts.push(`diagnostics=${diagnostics.join(" | ")}`);
250	  }
251	  return new Error(
252	    `bundled ${params.capabilityLabel} contract load failed for ${params.pluginId}: ${detailParts.join("; ")}`,
253	  );
254	}
