256	function loadScopedCapabilityRuntimeRegistryEntries<T>(params: {
257	  pluginId: string;
258	  capabilityLabel: string;
259	  loadEntries: (registry: BundledCapabilityRuntimeRegistry) => T[];
260	  loadDeclaredIds: (
261	    plugin: BundledCapabilityRuntimeRegistry["plugins"][number],
262	  ) => readonly string[];
263	}): T[] {
264	  let lastFailure: Error | undefined;
265	
266	  for (let attempt = 0; attempt < 2; attempt += 1) {
267	    const registry = loadBundledCapabilityRuntimeRegistry({
268	      pluginIds: [params.pluginId],
269	      pluginSdkResolution: "dist",
270	    });
271	    const entries = params.loadEntries(registry);
272	    if (entries.length > 0) {
273	      return entries;
274	    }
275	
276	    const plugin = registry.plugins.find((entry) => entry.id === params.pluginId);
277	    lastFailure = formatBundledCapabilityPluginLoadError({
278	      pluginId: params.pluginId,
279	      capabilityLabel: params.capabilityLabel,
280	      registry,
281	    });
282	    const shouldRetry =
283	      attempt === 0 &&
284	      (!plugin || plugin.status !== "loaded" || params.loadDeclaredIds(plugin).length === 0);
285	    if (!shouldRetry) {
286	      break;
287	    }
288	  }
289	
290	  throw (
291	    lastFailure ??
292	    new Error(
293	      `bundled ${params.capabilityLabel} contract load failed for ${params.pluginId}: no entries`,
294	    )
295	  );
296	}
