304	function loadProviderContractEntriesForPluginId(pluginId: string): ProviderContractEntry[] {
305	  if (providerContractRegistryCache) {
306	    return providerContractRegistryCache.filter((entry) => entry.pluginId === pluginId);
307	  }
308	
309	  const cache =
310	    providerContractRegistryByPluginIdCache ?? new Map<string, ProviderContractEntry[]>();
311	  providerContractRegistryByPluginIdCache = cache;
312	  const cached = cache.get(pluginId);
313	  if (cached) {
314	    return cached;
315	  }
316	
317	  try {
318	    providerContractLoadError = undefined;
319	    const entries = loadScopedCapabilityRuntimeRegistryEntries({
320	      pluginId,
321	      capabilityLabel: "provider",
322	      loadEntries: (registry) =>
323	        registry.providers
324	          .filter((entry) => entry.pluginId === pluginId)
325	          .map((entry) => ({
326	            pluginId: entry.pluginId,
327	            provider: entry.provider,
328	          })),
329	      loadDeclaredIds: (plugin) => plugin.providerIds,
330	    }).map((entry) => ({
331	      pluginId: entry.pluginId,
332	      provider: entry.provider,
333	    }));
334	    cache.set(pluginId, entries);
335	    return entries;
336	  } catch (error) {
337	    providerContractLoadError = error instanceof Error ? error : new Error(String(error));
338	    cache.set(pluginId, []);
339	    return [];
340	  }
341	}
