378	function resolveWebSearchCredentialValue(provider: WebSearchProviderPlugin): unknown {
379	  if (provider.requiresCredential === false) {
380	    return `${provider.id}-no-key-needed`;
381	  }
382	  const envVar = provider.envVars.find((entry) => entry.trim().length > 0);
383	  if (!envVar) {
384	    return `${provider.id}-test`;
385	  }
386	  if (envVar === "OPENROUTER_API_KEY") {
387	    return "openrouter-test";
388	  }
389	  return normalizeLowercaseStringOrEmpty(envVar).includes("api_key")
390	    ? `${provider.id}-test`
391	    : "sk-test";
392	}
