608	function createLazyArrayView<T>(load: () => T[]): T[] {
609	  return new Proxy([] as T[], {
610	    get(_target, prop) {
611	      const actual = load();
612	      const value = Reflect.get(actual, prop, actual);
613	      return typeof value === "function" ? value.bind(actual) : value;
614	    },
615	    has(_target, prop) {
616	      return Reflect.has(load(), prop);
617	    },
618	    ownKeys() {
619	      return Reflect.ownKeys(load());
620	    },
621	    getOwnPropertyDescriptor(_target, prop) {
622	      const actual = load();
623	      const descriptor = Reflect.getOwnPropertyDescriptor(actual, prop);
624	      if (descriptor) {
625	        return descriptor;
626	      }
627	      if (Reflect.has(actual, prop)) {
628	        return {
629	          configurable: true,
630	          enumerable: true,
631	          writable: false,
632	          value: Reflect.get(actual, prop, actual),
633	        };
634	      }
635	      return undefined;
636	    },
637	  });
638	}
