653	export function requireProviderContractProvider(providerId: string): ProviderPlugin {
654	  const pluginIds = resolveBundledProviderContractPluginIdsByProviderId().get(providerId) ?? [];
655	  const entries = loadProviderContractEntriesForPluginIds(pluginIds);
656	  const provider = entries.find((entry) => entry.provider.id === providerId)?.provider;
657	  if (!provider) {
658	    const pluginScopedProviders = [
659	      ...new Map(entries.map((entry) => [entry.provider.id, entry.provider])).values(),
660	    ];
661	    if (pluginIds.length === 1 && pluginScopedProviders.length === 1) {
662	      return pluginScopedProviders[0];
663	    }
664	    if (providerContractLoadError) {
665	      throw new Error(
666	        `provider contract entry missing for ${providerId}; bundled provider registry failed to load: ${providerContractLoadError.message}`,
667	      );
668	    }
669	    throw new Error(`provider contract entry missing for ${providerId}`);
670	  }
671	  return provider;
672	}
