220	function resolveManifestCacheMs(env: NodeJS.ProcessEnv): number {
221	  const raw = env.OPENCLAW_PLUGIN_MANIFEST_CACHE_MS?.trim();
222	  if (raw === "" || raw === "0") {
223	    return 0;
224	  }
225	  if (!raw) {
226	    return DEFAULT_MANIFEST_CACHE_MS;
227	  }
228	  const parsed = Number.parseInt(raw, 10);
229	  if (!Number.isFinite(parsed)) {
230	    return DEFAULT_MANIFEST_CACHE_MS;
231	  }
232	  return Math.max(0, parsed);
233	}
