243	function buildCacheKey(params: {
244	  workspaceDir?: string;
245	  plugins: NormalizedPluginsConfig;
246	  env: NodeJS.ProcessEnv;
247	}): string {
248	  const { roots, loadPaths } = resolvePluginCacheInputs({
249	    workspaceDir: params.workspaceDir,
250	    loadPaths: params.plugins.loadPaths,
251	    env: params.env,
252	  });
253	  const workspaceKey = roots.workspace ?? "";
254	  const configExtensionsRoot = roots.global;
255	  const bundledRoot = roots.stock ?? "";
256	  const runtimeServiceVersion = resolveCompatibilityHostVersion(params.env);
257	  // The manifest registry only depends on where plugins are discovered from (workspace + load paths).
258	  // It does not depend on allow/deny/entries enable-state, so exclude those for higher cache hit rates.
259	  return `${workspaceKey}::${configExtensionsRoot}::${bundledRoot}::${runtimeServiceVersion}::${JSON.stringify(loadPaths)}`;
260	}
