417	function matchesInstalledPluginRecord(params: {
418	  pluginId: string;
419	  candidate: PluginCandidate;
420	  config?: OpenClawConfig;
421	  env: NodeJS.ProcessEnv;
422	}): boolean {
423	  if (params.candidate.origin !== "global") {
424	    return false;
425	  }
426	  const record = params.config?.plugins?.installs?.[params.pluginId];
427	  if (!record) {
428	    return false;
429	  }
430	  const candidateSource = resolveUserPath(params.candidate.source, params.env);
431	  const trackedPaths = [record.installPath, record.sourcePath]
432	    .filter((entry): entry is string => typeof entry === "string" && entry.trim().length > 0)
433	    .map((entry) => resolveUserPath(entry, params.env));
434	  if (trackedPaths.length === 0) {
435	    return false;
436	  }
437	  return trackedPaths.some((trackedPath) => {
438	    return candidateSource === trackedPath || isPathInside(trackedPath, candidateSource);
439	  });
440	}
