442	function resolveDuplicatePrecedenceRank(params: {
443	  pluginId: string;
444	  candidate: PluginCandidate;
445	  config?: OpenClawConfig;
446	  env: NodeJS.ProcessEnv;
447	}): number {
448	  if (params.candidate.origin === "config") {
449	    return 0;
450	  }
451	  if (
452	    params.candidate.origin === "global" &&
453	    matchesInstalledPluginRecord({
454	      pluginId: params.pluginId,
455	      candidate: params.candidate,
456	      config: params.config,
457	      env: params.env,
458	    })
459	  ) {
460	    return 1;
461	  }
462	  if (params.candidate.origin === "bundled") {
463	    // Bundled plugin ids are reserved unless the operator explicitly overrides them.
464	    return 2;
465	  }
466	  if (params.candidate.origin === "workspace") {
467	    return 3;
468	  }
469	  return 4;
470	}
