472	export function loadPluginManifestRegistry(
473	  params: {
474	    config?: OpenClawConfig;
475	    workspaceDir?: string;
476	    cache?: boolean;
477	    env?: NodeJS.ProcessEnv;
478	    candidates?: PluginCandidate[];
479	    diagnostics?: PluginDiagnostic[];
480	  } = {},
481	): PluginManifestRegistry {
482	  const config = params.config ?? {};
483	  const normalized = normalizePluginsConfigWithResolver(config.plugins);
484	  const env = params.env ?? process.env;
485	  const cacheKey = buildCacheKey({ workspaceDir: params.workspaceDir, plugins: normalized, env });
486	  const cacheEnabled = params.cache !== false && shouldUseManifestCache(env);
487	  if (cacheEnabled) {
488	    const cached = registryCache.get(cacheKey);
489	    if (cached && cached.expiresAt > Date.now()) {
490	      return cached.registry;
491	    }
492	  }
493	
494	  const discovery = params.candidates
495	    ? {
496	        candidates: params.candidates,
497	        diagnostics: params.diagnostics ?? [],
498	      }
499	    : discoverOpenClawPlugins({
500	        workspaceDir: params.workspaceDir,
501	        extraPaths: normalized.loadPaths,
502	        cache: params.cache,
503	        env,
504	      });
505	  const diagnostics: PluginDiagnostic[] = [...discovery.diagnostics];
506	  const candidates: PluginCandidate[] = discovery.candidates;
507	  const records: PluginManifestRecord[] = [];
508	  const seenIds = new Map<string, SeenIdEntry>();
509	  const realpathCache = new Map<string, string>();
510	  const currentHostVersion = resolveCompatibilityHostVersion(env);
511	
512	  for (const candidate of candidates) {
513	    const rejectHardlinks = candidate.origin !== "bundled";
514	    const isBundleRecord = (candidate.format ?? "openclaw") === "bundle";
515	    const manifestRes:
516	      | ReturnType<typeof loadPluginManifest>
517	      | ReturnType<typeof loadBundleManifest>
518	      | { ok: true; manifest: PluginManifest; manifestPath: string } =
519	      candidate.origin === "bundled" && candidate.bundledManifest && candidate.bundledManifestPath
520	        ? {
521	            ok: true,
522	            manifest: candidate.bundledManifest,
523	            manifestPath: candidate.bundledManifestPath,
524	          }
525	        : isBundleRecord && candidate.bundleFormat
526	          ? loadBundleManifest({
527	              rootDir: candidate.rootDir,
528	              bundleFormat: candidate.bundleFormat,
529	              rejectHardlinks,
530	            })
531	          : loadPluginManifest(candidate.rootDir, rejectHardlinks);
532	    if (!manifestRes.ok) {
533	      diagnostics.push({
534	        level: "error",
535	        message: manifestRes.error,
536	        source: manifestRes.manifestPath,
537	      });
538	      continue;
539	    }
540	    const manifest = manifestRes.manifest;
541	    const minHostVersionCheck = checkMinHostVersion({
542	      currentVersion: currentHostVersion,
543	      minHostVersion: candidate.packageManifest?.install?.minHostVersion,
544	    });
545	    if (!minHostVersionCheck.ok) {
546	      const packageManifestSource = path.join(
547	        candidate.packageDir ?? candidate.rootDir,
548	        "package.json",
549	      );
550	      diagnostics.push({
551	        level: minHostVersionCheck.kind === "unknown_host_version" ? "warn" : "error",
552	        pluginId: manifest.id,
553	        source: packageManifestSource,
554	        message:
555	          minHostVersionCheck.kind === "invalid"
556	            ? `plugin manifest invalid | ${minHostVersionCheck.error}`
557	            : minHostVersionCheck.kind === "unknown_host_version"
558	              ? `plugin requires OpenClaw >=${minHostVersionCheck.requirement.minimumLabel}, but this host version could not be determined; skipping load`
559	              : `plugin requires OpenClaw >=${minHostVersionCheck.requirement.minimumLabel}, but this host is ${minHostVersionCheck.currentVersion}; skipping load`,
560	      });
561	      continue;
562	    }
563	
564	    const configSchema = "configSchema" in manifest ? manifest.configSchema : undefined;
565	    const schemaCacheKey = (() => {
566	      if (!configSchema) {
567	        return undefined;
568	      }
569	      const manifestMtime = safeStatMtimeMs(manifestRes.manifestPath);
570	      return manifestMtime
571	        ? `${manifestRes.manifestPath}:${manifestMtime}`
572	        : manifestRes.manifestPath;
573	    })();
574	
575	    const existing = seenIds.get(manifest.id);
576	    if (existing) {
577	      // Check whether both candidates point to the same physical directory
578	      // (e.g. via symlinks or different path representations). If so, this
579	      // is a false-positive duplicate and can be silently skipped.
580	      const samePath = existing.candidate.rootDir === candidate.rootDir;
581	      const samePlugin = (() => {
582	        if (samePath) {
583	          return true;
584	        }
585	        const existingReal = safeRealpathSync(existing.candidate.rootDir, realpathCache);
586	        const candidateReal = safeRealpathSync(candidate.rootDir, realpathCache);
587	        return Boolean(existingReal && candidateReal && existingReal === candidateReal);
588	      })();
589	      if (samePlugin) {
590	        // Prefer higher-precedence origins even if candidates are passed in
591	        // an unexpected order (config > workspace > global > bundled).
592	        if (PLUGIN_ORIGIN_RANK[candidate.origin] < PLUGIN_ORIGIN_RANK[existing.candidate.origin]) {
593	          records[existing.recordIndex] = isBundleRecord
594	            ? buildBundleRecord({
595	                manifest: manifest as Parameters<typeof buildBundleRecord>[0]["manifest"],
596	                candidate,
597	                manifestPath: manifestRes.manifestPath,
598	              })
599	            : buildRecord({
600	                manifest: manifest as PluginManifest,
601	                candidate,
602	                manifestPath: manifestRes.manifestPath,
603	                schemaCacheKey,
604	                configSchema,
605	              });
606	          seenIds.set(manifest.id, { candidate, recordIndex: existing.recordIndex });
607	        }
608	        continue;
609	      }
610	      diagnostics.push({
611	        level: "warn",
612	        pluginId: manifest.id,
613	        source: candidate.source,
614	        message:
615	          resolveDuplicatePrecedenceRank({
616	            pluginId: manifest.id,
617	            candidate,
618	            config,
619	            env,
620	          }) <
621	          resolveDuplicatePrecedenceRank({
622	            pluginId: manifest.id,
623	            candidate: existing.candidate,
624	            config,
625	            env,
626	          })
627	            ? `duplicate plugin id detected; ${existing.candidate.origin} plugin will be overridden by ${candidate.origin} plugin (${candidate.source})`
628	            : `duplicate plugin id detected; ${candidate.origin} plugin will be overridden by ${existing.candidate.origin} plugin (${candidate.source})`,
629	      });
630	    } else {
631	      seenIds.set(manifest.id, { candidate, recordIndex: records.length });
632	    }
633	
634	    records.push(
635	      isBundleRecord
636	        ? buildBundleRecord({
637	            manifest: manifest as Parameters<typeof buildBundleRecord>[0]["manifest"],
638	            candidate,
639	            manifestPath: manifestRes.manifestPath,
640	          })
641	        : buildRecord({
642	            manifest: manifest as PluginManifest,
643	            candidate,
644	            manifestPath: manifestRes.manifestPath,
645	            schemaCacheKey,
646	            configSchema,
647	          }),
648	    );
649	  }
650	
651	  const registry = { plugins: records, diagnostics };
652	  if (cacheEnabled) {
653	    const ttl = resolveManifestCacheMs(env);
654	    if (ttl > 0) {
655	      registryCache.set(cacheKey, { expiresAt: Date.now() + ttl, registry });
656	    }
657	  }
658	  return registry;
659	}
