253	/**
254	 * On Windows, the Node.js ESM loader requires absolute paths to be expressed
255	 * as file:// URLs (e.g. file:///C:/Users/...). Raw drive-letter paths like
256	 * C:\... are rejected with ERR_UNSUPPORTED_ESM_URL_SCHEME because the loader
257	 * mistakes the drive letter for an unknown URL scheme.
258	 *
259	 * This helper converts Windows absolute import specifiers to file:// URLs and
260	 * leaves everything else unchanged.
261	 */
262	function toSafeImportPath(specifier: string): string {
263	  if (process.platform !== "win32") {
264	    return specifier;
265	  }
266	  if (specifier.startsWith("file://")) {
267	    return specifier;
268	  }
269	  if (path.win32.isAbsolute(specifier)) {
270	    const normalizedSpecifier = specifier.replaceAll("\\", "/");
271	    if (normalizedSpecifier.startsWith("//")) {
272	      return new URL(`file:${encodeURI(normalizedSpecifier)}`).href;
273	    }
274	    return new URL(`file:///${encodeURI(normalizedSpecifier)}`).href;
275	  }
276	  return specifier;
277	}
