428	function buildActivationMetadataHash(params: {
429	  activationSource: PluginActivationConfigSource;
430	  autoEnabledReasons: Readonly<Record<string, string[]>>;
431	}): string {
432	  const enabledSourceChannels = Object.entries(
433	    (params.activationSource.rootConfig?.channels as Record<string, unknown>) ?? {},
434	  )
435	    .filter(([, value]) => {
436	      if (!value || typeof value !== "object" || Array.isArray(value)) {
437	        return false;
438	      }
439	      return (value as { enabled?: unknown }).enabled === true;
440	    })
441	    .map(([channelId]) => channelId)
442	    .toSorted((left, right) => left.localeCompare(right));
443	  const pluginEntryStates = Object.entries(params.activationSource.plugins.entries)
444	    .map(([pluginId, entry]) => [pluginId, entry?.enabled ?? null] as const)
445	    .toSorted(([left], [right]) => left.localeCompare(right));
446	  const autoEnableReasonEntries = Object.entries(params.autoEnabledReasons)
447	    .map(([pluginId, reasons]) => [pluginId, [...reasons]] as const)
448	    .toSorted(([left], [right]) => left.localeCompare(right));
449	
450	  return createHash("sha256")
451	    .update(
452	      JSON.stringify({
453	        enabled: params.activationSource.plugins.enabled,
454	        allow: params.activationSource.plugins.allow,
455	        deny: params.activationSource.plugins.deny,
456	        memorySlot: params.activationSource.plugins.slots.memory,
457	        entries: pluginEntryStates,
458	        enabledChannels: enabledSourceChannels,
459	        autoEnabledReasons: autoEnableReasonEntries,
460	      }),
461	    )
462	    .digest("hex");
