529	function getCompatibleActivePluginRegistry(
530	  options: PluginLoadOptions = {},
531	): PluginRegistry | undefined {
532	  const activeRegistry = getActivePluginRegistry() ?? undefined;
533	  if (!activeRegistry) {
534	    return undefined;
535	  }
536	  if (!hasExplicitCompatibilityInputs(options)) {
537	    return activeRegistry;
538	  }
539	  const activeCacheKey = getActivePluginRegistryKey();
540	  if (!activeCacheKey) {
541	    return undefined;
542	  }
543	  const loadContext = resolvePluginLoadCacheContext(options);
544	  if (loadContext.cacheKey === activeCacheKey) {
545	    return activeRegistry;
546	  }
547	  if (
548	    loadContext.runtimeSubagentMode === "default" &&
549	    getActivePluginRuntimeSubagentMode() === "gateway-bindable"
550	  ) {
551	    const gatewayBindableCacheKey = resolvePluginLoadCacheContext({
552	      ...options,
553	      runtimeOptions: {
554	        ...options.runtimeOptions,
555	        allowGatewaySubagentBinding: true,
556	      },
557	    }).cacheKey;
558	    if (gatewayBindableCacheKey === activeCacheKey) {
559	      return activeRegistry;
560	    }
561	  }
562	  return undefined;
563	}
564	
565	export function resolveRuntimePluginRegistry(
566	  options?: PluginLoadOptions,
567	): PluginRegistry | undefined {
568	  if (!options || !hasExplicitCompatibilityInputs(options)) {
569	    return getCompatibleActivePluginRegistry();
570	  }
571	  const compatible = getCompatibleActivePluginRegistry(options);
572	  if (compatible) {
573	    return compatible;
574	  }
575	  // Helper/runtime callers should not recurse into the same snapshot load while
576	  // plugin registration is still in flight. Let direct loadOpenClawPlugins(...)
577	  // callers surface the hard error instead.
578	  if (isPluginRegistryLoadInFlight(options)) {
579	    return undefined;
580	  }
581	  return loadOpenClawPlugins(options);
582	}
583	
584	export function resolvePluginRegistryLoadCacheKey(options: PluginLoadOptions = {}): string {
585	  return resolvePluginLoadCacheContext(options).cacheKey;
586	}
587	
588	export function isPluginRegistryLoadInFlight(options: PluginLoadOptions = {}): boolean {
589	  return inFlightPluginRegistryLoads.has(resolvePluginRegistryLoadCacheKey(options));
590	}
591	
592	export function resolveCompatibleRuntimePluginRegistry(
593	  options?: PluginLoadOptions,
594	): PluginRegistry | undefined {
595	  // Check whether the active runtime registry is already compatible with these
596	  // load options. Unlike resolveRuntimePluginRegistry, this never triggers a
597	  // fresh plugin load on cache miss.
598	  return getCompatibleActivePluginRegistry(options);
599	}

